"""
============================================================
МОДУЛЬ: views.py
============================================================
НАЗНАЧЕНИЕ: Содержит представления (контроллеры) для обработки HTTP-запросов

АВТОР: Студент группы М3О-217БВ
ДАТА СОЗДАНИЯ: 2026-04-02
ПОСЛЕДНЕЕ ИЗМЕНЕНИЕ: 2026-04-02

ОПИСАНИЕ:
    Модуль включает следующие представления:
    1. index - главная страница со списком сотрудников
    2. login_view - страница входа в систему
    3. logout - выход из системы
    4. employee_create - добавление нового сотрудника (только директор)
    5. employee_update - редактирование сотрудника (директор и заместитель)
    6. employee_delete - удаление сотрудника (только директор)

ЗАВИСИМОСТИ:
    - django.shortcuts - для рендеринга шаблонов и редиректов
    - django.http - для работы с HTTP-запросами
    - django.contrib.messages - для отображения уведомлений
    - .forms - для работы с формами
    - .models - для работы с моделями
============================================================
"""

# Импорт утилит для работы с запросами и ответами
from django.shortcuts import render, redirect, get_object_or_404
# Импорт класса для типизации HTTP-запроса
from django.http import HttpRequest
# Импорт системы сообщений для уведомлений пользователя
from django.contrib import messages
# Импорт форм
from .forms import LoginForm, EmployeeForm
# Импорт моделей
from .models import Logins, Emploees


def index(request: HttpRequest):
    """
    ============================================================
    ФУНКЦИЯ: index (Главная страница)
    ============================================================
    НАЗНАЧЕНИЕ: Отображает список сотрудников с учетом прав доступа
    
    ПАРАМЕТРЫ:
        request (HttpRequest): HTTP-запрос от клиента
    
    ВОЗВРАЩАЕТ:
        HttpResponse: Отрендеренный шаблон со списком сотрудников
    
    АЛГОРИТМ:
        1. Определение статуса пользователя (гость/авторизован)
        2. Получение списка сотрудников из БД
        3. Настройка прав доступа в зависимости от роли
        4. Формирование контекста для шаблона
        5. Рендеринг шаблона
    
    ИСТОРИЯ ИЗМЕНЕНИЙ:
        2026-04-02: Создание функции
    ============================================================
    """
    
    # ============================================================
    # БЛОК 1: ОПРЕДЕЛЕНИЕ СТАТУСА ПОЛЬЗОВАТЕЛЯ
    # ============================================================
    
    # Проверка: авторизован ли пользователь (есть ли в сессии is_authenticated)
    # get() возвращает значение или False по умолчанию
    if not request.session.get('is_authenticated', False):
        # Если не авторизован - устанавливаем гостевую сессию
        request.session['is_guest'] = True           # Флаг гостя
        request.session['is_authenticated'] = False  # Не авторизован
        # Локальные переменные для шаблона
        is_guest = True
        is_authenticated = False
        user_role = None      # Роль отсутствует
        user_name = None      # Имя отсутствует
    else:
        # Пользователь авторизован
        is_authenticated = True
        is_guest = False
        # Получение роли и имени из сессии
        user_role = request.session.get('user_role')
        user_name = request.session.get('user_name')
    
    # ============================================================
    # БЛОК 2: ПОЛУЧЕНИЕ ДАННЫХ ИЗ БАЗЫ ДАННЫХ
    # ============================================================
    
    # Получение всех сотрудников из БД
    # order_by() - сортировка по фамилии и имени (по возрастанию)
    employees = Emploees.objects.all().order_by('last_name', 'first_name')
    
    # ============================================================
    # БЛОК 3: НАСТРОЙКА ПРАВ ДОСТУПА
    # ============================================================
    
    # Инициализация флагов доступа (по умолчанию все запрещено)
    show_full_info = False  # Показывать ли адрес (гость не видит)
    can_add = False         # Может ли добавлять сотрудников
    can_change = False      # Может ли редактировать сотрудников
    can_delete = False      # Может ли удалять сотрудников
    
    # Права для гостя
    if is_guest:
        show_full_info = False  # Гость не видит адрес
        can_add = False
        can_change = False
        can_delete = False
    
    # Права для авторизованного пользователя
    elif is_authenticated:
        show_full_info = True   # Все авторизованные видят полную информацию
        
        # Директор - все права
        if user_role == 'director':
            can_add = True
            can_change = True
            can_delete = True
        
        # Заместитель директора - только редактирование
        elif user_role == 'deputy':
            can_add = False
            can_change = True
            can_delete = False
        
        # Секретарь - только просмотр
        elif user_role == 'secretary':
            can_add = False
            can_change = False
            can_delete = False
    
    # ============================================================
    # БЛОК 4: ФОРМИРОВАНИЕ КОНТЕКСТА И РЕНДЕРИНГ
    # ============================================================
    
    # Словарь контекста для передачи в шаблон
    context = {
        'title': 'Список сотрудников',      # Заголовок страницы
        'employees': employees,             # Список сотрудников
        'show_full_info': show_full_info,   # Флаг показа адреса
        'can_add': can_add,                 # Флаг добавления
        'can_change': can_change,           # Флаг редактирования
        'can_delete': can_delete,           # Флаг удаления
        'is_authenticated': is_authenticated,  # Флаг авторизации
        'is_guest': is_guest,               # Флаг гостя
        'user_role': user_role,             # Роль пользователя
        'user_name': user_name,             # Имя пользователя
    }
    
    # Рендеринг HTML-шаблона с переданным контекстом
    return render(request, 'dist/emploees.html', context)


def login_view(request: HttpRequest):
    """
    ============================================================
    ФУНКЦИЯ: login_view (Страница входа)
    ============================================================
    НАЗНАЧЕНИЕ: Аутентификация пользователя и создание сессии
    
    ПАРАМЕТРЫ:
        request (HttpRequest): HTTP-запрос от клиента
    
    ВОЗВРАЩАЕТ:
        HttpResponse: Страницу входа или редирект на главную
    
    АЛГОРИТМ:
        1. Проверка, не авторизован ли уже пользователь
        2. Удаление гостевой сессии (если есть)
        3. Обработка POST-запроса (валидация формы)
        4. Сохранение данных пользователя в сессию
        5. Редирект на главную при успехе
    
    ИСТОРИЯ ИЗМЕНЕНИЙ:
        2026-04-02: Создание функции
    ============================================================
    """
    
    # ============================================================
    # БЛОК 1: ПРОВЕРКА УЖЕ АВТОРИЗОВАННОГО ПОЛЬЗОВАТЕЛЯ
    # ============================================================
    
    # Если пользователь уже авторизован - перенаправляем на главную
    if request.session.get('is_authenticated', False):
        messages.info(request, 'Вы уже вошли в систему')
        return redirect('index')
    
    # ============================================================
    # БЛОК 2: УДАЛЕНИЕ ГОСТЕВОЙ СЕССИИ
    # ============================================================
    
    # Если есть гостевая сессия - удаляем её
    if 'is_guest' in request.session:
        del request.session['is_guest']
    
    # ============================================================
    # БЛОК 3: ОБРАБОТКА POST-ЗАПРОСА
    # ============================================================
    
    if request.method == 'POST':
        # Создание формы с данными из запроса
        form = LoginForm(request.POST)
        # Валидация формы (вызывается метод clean())
        if form.is_valid():
            # Получение объекта пользователя из формы
            user = form.cleaned_data['user']
            
            # Сохранение данных в сессию
            request.session['is_authenticated'] = True    # Флаг авторизации
            request.session['user_id'] = user.id          # ID учетной записи
            request.session['user_login'] = user.login    # Логин
            request.session['user_role'] = user.employee.position  # Роль
            request.session['user_name'] = user.employee.full_name # ФИО
            
            # Сообщение об успешном входе
            messages.success(request, f'Добро пожаловать, {user.employee.full_name}!')
            # Перенаправление на главную
            return redirect('index')
    else:
        # GET-запрос: создание пустой формы
        form = LoginForm()
    
    # ============================================================
    # БЛОК 4: РЕНДЕРИНГ СТРАНИЦЫ ВХОДА
    # ============================================================
    
    context = {
        'title': 'Вход в систему',
        'form': form,
    }
    return render(request, 'dist/login.html', context)


def logout(request: HttpRequest):
    """
    ============================================================
    ФУНКЦИЯ: logout (Выход из системы)
    ============================================================
    НАЗНАЧЕНИЕ: Завершение сессии пользователя
    
    ПАРАМЕТРЫ:
        request (HttpRequest): HTTP-запрос от клиента
    
    ВОЗВРАЩАЕТ:
        HttpResponse: Редирект на главную страницу
    
    АЛГОРИТМ:
        1. Получение имени пользователя из сессии
        2. Очистка всей сессии (flush)
        3. Отображение сообщения о выходе
        4. Редирект на главную
    
    ИСТОРИЯ ИЗМЕНЕНИЙ:
        2026-04-02: Создание функции
    ============================================================
    """
    
    # Получение имени пользователя из сессии (если есть)
    user_name = request.session.get('user_name', '')
    
    # Полная очистка сессии (удаляет все данные)
    request.session.flush()
    
    # Отображение сообщения о выходе
    if user_name:
        messages.success(request, f'До свидания, {user_name}!')
    else:
        messages.success(request, 'Вы вышли из системы')
    
    # Перенаправление на главную страницу
    return redirect('index')


def employee_create(request: HttpRequest):
    """
    ============================================================
    ФУНКЦИЯ: employee_create (Добавление сотрудника)
    ============================================================
    НАЗНАЧЕНИЕ: Создание нового сотрудника (только для директора)
    
    ПАРАМЕТРЫ:
        request (HttpRequest): HTTP-запрос от клиента
    
    ВОЗВРАЩАЕТ:
        HttpResponse: Форму добавления или страницу с учетными данными
    
    ПРАВА ДОСТУПА:
        - Только директор может добавлять сотрудников
    
    АЛГОРИТМ:
        1. Проверка прав доступа (не гость, авторизован, директор)
        2. Обработка POST-запроса (сохранение сотрудника)
        3. Отображение сгенерированных логина и пароля
    
    ИСТОРИЯ ИЗМЕНЕНИЙ:
        2026-04-02: Создание функции
    ============================================================
    """
    
    # ============================================================
    # БЛОК 1: ПРОВЕРКА ПРАВ ДОСТУПА
    # ============================================================
    
    # Проверка: не гость ли пользователь
    if request.session.get('is_guest', False):
        messages.error(request, 'У вас нет прав для добавления сотрудников')
        return redirect('index')
    
    # Проверка: авторизован ли пользователь
    if not request.session.get('is_authenticated', False):
        messages.error(request, 'Необходимо войти в систему')
        return redirect('login')
    
    # Проверка: имеет ли пользователь роль директора
    user_role = request.session.get('user_role')
    if user_role != 'director':
        messages.error(request, 'Только директор может добавлять сотрудников')
        return redirect('index')
    
    # ============================================================
    # БЛОК 2: ОБРАБОТКА POST-ЗАПРОСА
    # ============================================================
    
    if request.method == 'POST':
        # Создание формы с данными из запроса
        form = EmployeeForm(request.POST)
        # Валидация формы
        if form.is_valid():
            # Сохранение сотрудника и получение учетных данных
            # Метод save() возвращает кортеж (сотрудник, логин, пароль)
            employee, login, password = form.save()
            
            # Отображение страницы с учетными данными
            return render(request, 'dist/employee_created.html', {
                'title': 'Создание работника',
                'employee': employee,
                'login': login,
                'password': password
            })
    else:
        # GET-запрос: создание пустой формы
        form = EmployeeForm()
    
    # ============================================================
    # БЛОК 3: РЕНДЕРИНГ ФОРМЫ ДОБАВЛЕНИЯ
    # ============================================================
    
    context = {
        'title': 'Создание работника',
        'form': form,
        'action': 'create'  # Для определения режима в шаблоне
    }
    return render(request, 'dist/employee_form.html', context)


def employee_update(request: HttpRequest, pk):
    """
    ============================================================
    ФУНКЦИЯ: employee_update (Редактирование сотрудника)
    ============================================================
    НАЗНАЧЕНИЕ: Редактирование данных сотрудника (директор и заместитель)
    
    ПАРАМЕТРЫ:
        request (HttpRequest): HTTP-запрос от клиента
        pk (int): Первичный ключ сотрудника
    
    ВОЗВРАЩАЕТ:
        HttpResponse: Форму редактирования или редирект на главную
    
    ПРАВА ДОСТУПА:
        - Директор и заместитель могут редактировать
    
    ИСТОРИЯ ИЗМЕНЕНИЙ:
        2026-04-02: Создание функции
    ============================================================
    """
    
    # ============================================================
    # БЛОК 1: ПРОВЕРКА ПРАВ ДОСТУПА
    # ============================================================
    
    # Проверка: не гость ли пользователь
    if request.session.get('is_guest', False):
        messages.error(request, 'У вас нет прав для редактирования')
        return redirect('index')
    
    # Проверка: авторизован ли пользователь
    if not request.session.get('is_authenticated', False):
        messages.error(request, 'Необходимо войти в систему')
        return redirect('login')
    
    # Проверка: имеет ли пользователь роль директора или заместителя
    user_role = request.session.get('user_role')
    if user_role not in ['director', 'deputy']:
        messages.error(request, 'У вас нет прав для редактирования')
        return redirect('index')
    
    # ============================================================
    # БЛОК 2: ПОЛУЧЕНИЕ ОБЪЕКТА СОТРУДНИКА
    # ============================================================
    
    # get_object_or_404 - получает сотрудника или возвращает 404
    employee = get_object_or_404(Emploees, pk=pk)
    
    # ============================================================
    # БЛОК 3: ОБРАБОТКА POST-ЗАПРОСА
    # ============================================================
    
    if request.method == 'POST':
        # Создание формы с данными из запроса
        # instance=employee - для редактирования существующего объекта
        # create_account=False - не создавать новую учетную запись
        form = EmployeeForm(request.POST, instance=employee, create_account=False)
        if form.is_valid():
            # Сохранение изменений (только данные сотрудника)
            form.save()
            # Сообщение об успешном обновлении
            messages.success(request, f'Данные сотрудника {employee.full_name} успешно обновлены')
            # Перенаправление на главную
            return redirect('index')
    else:
        # GET-запрос: создание формы с данными сотрудника
        # create_account=False - так как это редактирование
        form = EmployeeForm(instance=employee, create_account=False)
    
    # ============================================================
    # БЛОК 4: РЕНДЕРИНГ ФОРМЫ РЕДАКТИРОВАНИЯ
    # ============================================================
    
    context = {
        'title': 'Обновление данных о работнике',
        'form': form,
        'action': 'update',    # Для определения режима в шаблоне
        'employee': employee,  # Передача сотрудника для отображения
    }
    return render(request, 'dist/employee_form.html', context)


def employee_delete(request: HttpRequest, pk):
    """
    ============================================================
    ФУНКЦИЯ: employee_delete (Удаление сотрудника)
    ============================================================
    НАЗНАЧЕНИЕ: Удаление сотрудника из базы данных (только для директора)
    
    ПАРАМЕТРЫ:
        request (HttpRequest): HTTP-запрос от клиента
        pk (int): Первичный ключ сотрудника
    
    ВОЗВРАЩАЕТ:
        HttpResponse: Страницу подтверждения или редирект на главную
    
    ПРАВА ДОСТУПА:
        - Только директор может удалять сотрудников
    
    АЛГОРИТМ:
        1. Проверка прав доступа (директор)
        2. GET-запрос: отображение страницы подтверждения
        3. POST-запрос: удаление сотрудника из БД
    
    ИСТОРИЯ ИЗМЕНЕНИЙ:
        2026-04-02: Создание функции
    ============================================================
    """
    
    # ============================================================
    # БЛОК 1: ПРОВЕРКА ПРАВ ДОСТУПА
    # ============================================================
    
    # Проверка: не гость ли пользователь
    if request.session.get('is_guest', False):
        messages.error(request, 'У вас нет прав для удаления сотрудников')
        return redirect('index')
    
    # Проверка: авторизован ли пользователь
    if not request.session.get('is_authenticated', False):
        messages.error(request, 'Необходимо войти в систему')
        return redirect('login')
    
    # Проверка: имеет ли пользователь роль директора
    user_role = request.session.get('user_role')
    if user_role != 'director':
        messages.error(request, 'Только директор может удалять сотрудников')
        return redirect('index')
    
    # ============================================================
    # БЛОК 2: ПОЛУЧЕНИЕ ОБЪЕКТА СОТРУДНИКА
    # ============================================================
    
    # get_object_or_404 - получает сотрудника или возвращает 404
    employee = get_object_or_404(Emploees, pk=pk)
    
    # ============================================================
    # БЛОК 3: ОБРАБОТКА POST-ЗАПРОСА (ПОДТВЕРЖДЕНИЕ УДАЛЕНИЯ)
    # ============================================================
    
    if request.method == 'POST':
        # Сохранение имени сотрудника для сообщения (до удаления)
        employee_name = employee.full_name
        # Удаление сотрудника из БД (учетная запись удалится каскадно)
        employee.delete()
        # Сообщение об успешном удалении
        messages.success(request, f'Сотрудник {employee_name} успешно удален')
        # Перенаправление на главную
        return redirect('index')
    
    # ============================================================
    # БЛОК 4: РЕНДЕРИНГ СТРАНИЦЫ ПОДТВЕРЖДЕНИЯ
    # ============================================================
    
    context = {
        'title': 'Удалить работника из системы',
        'employee': employee,
    }
    return render(request, 'dist/employee_confirm_delete.html', context)